//! C-interface for the component.
//! This code must be unsafe.
//! Assumptions about correctness are introduced and need to be verified by other means.

use data::*;

#[cfg(test)]
use std::sync::Mutex;

#[cfg(not(test))]
extern "C" {
  fn put_out_val(value: *mut i32) -> bool;
  fn put_evt() -> bool;
}

pub fn unsafe_put_out_val(value: &i32) -> bool
{
  unsafe {
    return put_out_val(value as *const i32 as *mut i32);
  }
}

pub fn unsafe_put_evt() -> bool
{
  unsafe {
    return put_evt();
  }
}

//////////////////////////////////////////////////////////////////////////////////
// Testing Versions
//////////////////////////////////////////////////////////////////////////////////

#[cfg(test)]
lazy_static::lazy_static! {
  // simulate the global C variables that point to the microkit shared memory regions.  In a full
  // microkit system we would be able to mutate the shared memory for out ports since they're r/w,
  // but we couldn't do that for in ports since they are read-only
  pub static ref OUT_out_val: Mutex<Option<i32>> = Mutex::new(None);
  pub static ref OUT_evt: Mutex<Option<u8>> = Mutex::new(None);
}

#[cfg(test)]
pub fn initialize_test_globals() {
  unsafe {
    *OUT_out_val.lock().unwrap_or_else(|e| e.into_inner()) = None;
    *OUT_evt.lock().unwrap_or_else(|e| e.into_inner()) = None;
  }
}

#[cfg(test)]
pub fn put_out_val(value: *mut i32) -> bool
{
  unsafe {
    *OUT_out_val.lock().unwrap_or_else(|e| e.into_inner()) = Some(*value);
    return true;
  }
}

#[cfg(test)]
pub fn put_evt() -> bool
{
  unsafe {
    *OUT_evt.lock().unwrap_or_else(|e| e.into_inner()) = Some(0u8);
    return true;
  }
}
